function EmojiPrompt() {
  const POOLS = [
    { emojis: ['≡ƒÜÇ', '≡ƒìò', '≡ƒò╡∩╕ÅΓÇìΓÖé∩╕Å'], keywords: ['rocket', 'space', 'pizza', 'detective', 'mystery'] },
